Javascript.validate:
var val = Services.getValue(SumToPay.dataBinding);
var err = WPU.validateCurrency(val);
if( null == err )
{ 	var fVal = WPU.formatToTwoDP(val);
	Services.setValue(SumToPay.dataBinding, fVal);
}
return err;

