function DefaultCurrency327() {}
DefaultCurrency327.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency327.tabIndex = -1;
DefaultCurrency327.maxLength = 1;
DefaultCurrency327.isReadOnly = function(){return true;}
DefaultCurrency327.isTemporary = function(){return true;}
DefaultCurrency327.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency327.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
